import{r as e,o as a,c as d,a as t,w as i,F as r,d as n,b as s}from"./app.2e1eaa90.js";const l={},o=n('<h1 id="数据库-database" tabindex="-1"><a class="header-anchor" href="#数据库-database" aria-hidden="true">#</a> 数据库 (Database)</h1><h2 id="数据类型" tabindex="-1"><a class="header-anchor" href="#数据类型" aria-hidden="true">#</a> 数据类型</h2><h3 id="user" tabindex="-1"><a class="header-anchor" href="#user" aria-hidden="true">#</a> User</h3><ul><li><strong>id:</strong> <code>string</code> 内部编号</li><li><strong>name:</strong> <code>string</code> 用户昵称</li><li><strong>flag:</strong> <code>number</code> 状态标签</li><li><strong>authority:</strong> <code>number</code> 用户权限</li><li><strong>usage:</strong> <code>Record&lt;string, number&gt;</code> 指令调用次数</li><li><strong>timers:</strong> <code>Record&lt;string, number&gt;</code> 指令调用时间</li></ul><h3 id="channel" tabindex="-1"><a class="header-anchor" href="#channel" aria-hidden="true">#</a> Channel</h3><ul><li><strong>id:</strong> <code>string</code> 频道标识符</li><li><strong>flag:</strong> <code>number</code> 状态标签</li><li><strong>assignee:</strong> <code>string</code> 代理者</li></ul><h2 id="全局接口" tabindex="-1"><a class="header-anchor" href="#全局接口" aria-hidden="true">#</a> 全局接口</h2><h3 id="user-flag-channel-flag" tabindex="-1"><a class="header-anchor" href="#user-flag-channel-flag" aria-hidden="true">#</a> User.Flag, Channel.Flag</h3>',8),c=s("所有用户 / 频道状态标签构成的枚举类型。参见 "),h=s("状态标签"),g=s("。"),u=n('<h3 id="user-fields-channel-fields" tabindex="-1"><a class="header-anchor" href="#user-fields-channel-fields" aria-hidden="true">#</a> User.fields, Channel.fields</h3><p>所有用户 / 频道字段构成的列表。</p><h3 id="user-extend-getter-channel-extend-getter" tabindex="-1"><a class="header-anchor" href="#user-extend-getter-channel-extend-getter" aria-hidden="true">#</a> User.extend(getter), Channel.extend(getter)</h3><ul><li><strong>getter:</strong> <code>(type: string, id: string) =&gt; object</code> 新字段的初始化函数，返回值应该是一个由要扩展的字段和它们的默认值构成的键值对</li><li>返回值: <code>void</code></li></ul><p>扩展用户 / 频道字段。</p><h3 id="user-create-type-id-channel-create-type-id" tabindex="-1"><a class="header-anchor" href="#user-create-type-id-channel-create-type-id" aria-hidden="true">#</a> User.create(type, id), Channel.create(type, id)</h3><ul><li><strong>type:</strong> <code>string</code> 平台名</li><li><strong>id:</strong> <code>string</code> 用户 / 频道标识符</li><li>返回值: <code>User</code> / <code>Channel</code></li></ul><p>创建一个新用户 / 频道数据对象。</p><h3 id="tables-extend-name-config" tabindex="-1"><a class="header-anchor" href="#tables-extend-name-config" aria-hidden="true">#</a> Tables.extend(name, config?)</h3><ul><li><strong>name:</strong> <code>string</code> 数据表名</li><li><strong>config:</strong> <code>TableMeta</code> 表的基本配置 <ul><li><strong>config.primary:</strong> <code>string</code> 主键名，默认为 <code>&#39;id&#39;</code></li><li><strong>config.unique:</strong> <code>string[]</code> 值唯一的键名列表</li><li><strong>config.type:</strong> <code>string</code> 主键产生的方式，目前支持： <ul><li><code>incremental</code>: 检测目前最大的主键值，并增加 1 作为新的主键值</li></ul></li></ul></li></ul><p>扩展一个新的数据表。</p><h3 id="database-extend-database-extension" tabindex="-1"><a class="header-anchor" href="#database-extend-database-extension" aria-hidden="true">#</a> Database.extend(database, extension)</h3><ul><li><strong>database:</strong> <code>string | (new () =&gt; Database)</code> 要扩展的数据库类 <ul><li>如果传入一个字符串，则会将这个模块的默认导出作为目标类</li></ul></li><li><strong>extension:</strong> <code>Partial&lt;Database&gt; | ((Database: T) =&gt; void)</code><ul><li>如果传入一个对象，则表示要添加到原型链的方法</li><li>如果传入一个函数，则会传入上述类构造器并立即执行</li></ul></li></ul><p>扩展数据库的功能。</p><h2 id="数据库对象" tabindex="-1"><a class="header-anchor" href="#数据库对象" aria-hidden="true">#</a> 数据库对象</h2><p>一个 Database 对象代理了 Koishi 上下文绑定的应用实例有关的所有数据库访问。同时它具有注入特性，任何插件都可以自己定义数据库上的方法。本章主要介绍数据库的官方接口。注意：<strong>它们并不由 Koishi 自身实现，而是由每个数据库分别实现的</strong>。Koishi 只是提供了一套标准。</p><h3 id="db-get-table-query-fields" tabindex="-1"><a class="header-anchor" href="#db-get-table-query-fields" aria-hidden="true">#</a> db.get(table, query, fields?)</h3><h3 id="db-remove-table-query" tabindex="-1"><a class="header-anchor" href="#db-remove-table-query" aria-hidden="true">#</a> db.remove(table, query)</h3><h3 id="db-create-table-data" tabindex="-1"><a class="header-anchor" href="#db-create-table-data" aria-hidden="true">#</a> db.create(table, data)</h3><h3 id="db-update-table-data-key" tabindex="-1"><a class="header-anchor" href="#db-update-table-data-key" aria-hidden="true">#</a> db.update(table, data, key?)</h3><h3 id="db-getuser-type-id-fields" tabindex="-1"><a class="header-anchor" href="#db-getuser-type-id-fields" aria-hidden="true">#</a> db.getUser(type, id, fields?)</h3><ul><li><strong>type:</strong> <code>string</code> 平台名</li><li><strong>id:</strong> <code>string | string[]</code> 用户标识符</li><li><strong>fields:</strong> <code>User.Field[]</code> 请求的字段，默认为全部字段</li><li>返回值: <code>Promise&lt;User | User[]&gt;</code> 用户数据</li></ul><p>向数据库请求用户数据。如果传入的 id 是一个列表，则返回值也应当是一个列表。</p><div class="custom-container tip"><p class="custom-container-title">提示</p><p>尽管这里我们提供了 <code>fields</code> 参数用于对特定的数据库进行优化，但是如果你是数据库开发者，也完全可以忽略这个参数。只需要保证返回的数据满足用户数据格式，且包含在 <code>fields</code> 中的字段都存在即可。</p></div><h3 id="db-setuser-type-id-data" tabindex="-1"><a class="header-anchor" href="#db-setuser-type-id-data" aria-hidden="true">#</a> db.setUser(type, id, data)</h3><h3 id="db-createuser-type-id-data" tabindex="-1"><a class="header-anchor" href="#db-createuser-type-id-data" aria-hidden="true">#</a> db.createUser(type, id, data)</h3><ul><li><strong>type:</strong> <code>string</code> 平台名</li><li><strong>id:</strong> <code>string</code> 用户标识符</li><li><strong>data:</strong> <code>User</code> 要修改 / 添加的数据</li><li>返回值: <code>Promise&lt;void&gt;</code></li></ul><p>向数据库修改 / 添加用户数据。</p><h3 id="db-getchannel-type-id-fields" tabindex="-1"><a class="header-anchor" href="#db-getchannel-type-id-fields" aria-hidden="true">#</a> db.getChannel(type, id, fields?)</h3><ul><li><strong>type:</strong> <code>string</code> 平台名</li><li><strong>id:</strong> <code>string | string[]</code> 频道标识符</li><li><strong>fields:</strong> <code>ChannelField[]</code> 请求的字段，默认为全部字段</li><li>返回值: <code>Promise&lt;Channel | Channel[]&gt;</code> 频道数据</li></ul><p>向数据库请求频道数据。如果传入的 id 是一个列表，则返回值也应当是一个列表。</p><h3 id="db-getchannellist-fields-type-assignees" tabindex="-1"><a class="header-anchor" href="#db-getchannellist-fields-type-assignees" aria-hidden="true">#</a> db.getChannelList(fields?, type?, assignees?)</h3><ul><li><strong>fields:</strong> <code>ChannelField[]</code> 请求的字段，默认为全部字段</li><li><strong>type:</strong> <code>string</code> 平台名，默认为全平台</li><li><strong>assignees:</strong> <code>string[]</code> 代理者列表，默认为当前运行的全部机器人</li><li>返回值: <code>Promise&lt;Channel[]&gt;</code> 频道数据列表</li></ul><p>向数据库请求被特定机器人管理的所有频道数据。这里的两个参数可以写任意一个，都可以识别。</p><h3 id="db-setchannel-type-id-data" tabindex="-1"><a class="header-anchor" href="#db-setchannel-type-id-data" aria-hidden="true">#</a> db.setChannel(type, id, data)</h3><h3 id="db-createchannel-type-id-data" tabindex="-1"><a class="header-anchor" href="#db-createchannel-type-id-data" aria-hidden="true">#</a> db.createChannel(type, id, data)</h3><ul><li><strong>type:</strong> <code>string</code> 平台名</li><li><strong>id:</strong> <code>number</code> 频道标识符</li><li><strong>data:</strong> <code>Channel</code> 要修改 / 添加的数据</li><li>返回值: <code>Promise&lt;void&gt;</code></li></ul><p>向数据库修改 / 添加频道数据。</p>',38);l.render=function(n,s){const l=e("RouterLink");return a(),d(r,null,[o,t("p",null,[c,t(l,{to:"/guide/manage.html#%E7%8A%B6%E6%80%81%E6%A0%87%E7%AD%BE"},{default:i((()=>[h])),_:1}),g]),u],64)};export default l;
